graphql.query:
query GetOrderWithJoins($id: ID!) {
  order(id: $id) {
    id
    status
    total_amount
    customer_name
    items { product_name quantity unit_price }
    driver {
      id
      name
      vehicle_type
      status
      last_location { latitude longitude timestamp }
    }
    delivery {
      id
      status
      driver_name
      history {
        event_type
        created_at
      }
    }
  }
}

query InTransitDeliveries {
  deliveries(status: "IN_TRANSIT", limit: 20) {
    total
    deliveries {
      id
      delivery_address
      driver {
        id
        name
        last_location { latitude longitude }
      }
      order {
        customer_name
        total_amount
      }
    }
  }
}

query AllDeliveriesWithHistory {
  deliveries(limit: 5) {
    total
    deliveries {
      id
      status
      driver_name
      history { event_type created_at }
    }
  }
}

mutation CreateOrder($input: CreateOrderInput!) {
  createOrder(input: $input) {
    id
    status
    total_amount
    customer_name
    items { product_name quantity unit_price }
  }
}

mutation AdvanceDelivery($id: ID!, $newStatus: String!) {
  advanceDelivery(delivery_id: $id, new_status: $newStatus) {
    id
    status
    driver_name
    order {
      id
      status
    }
  }
}
